import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Header
import retrofit2.http.Path
import java.util.concurrent.TimeUnit

// API Interface
interface UserApiService {
    @GET("users/{id}")
    suspend fun getUserProfile(
        @Path("id") userId: Int,
        @Header("Authorization") authToken: String
    ): UserResponse
}

// Data Models
data class UserResponse(
    val id: Int,
    val name: String,
    val email: String
)

// Network Module
object NetworkModule {
    private const val BASE_URL_DEV = "https://dev.api.example.com/"
    private const val BASE_URL_STAGING = "https://staging.api.example.com/"
    private const val BASE_URL_PROD = "https://api.example.com/"
    
    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }
    
    private val okHttpClient = OkHttpClient.Builder()
        .addInterceptor(loggingInterceptor)
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(30, TimeUnit.SECONDS)
        .build()
    
    fun getRetrofit(environment: Environment): Retrofit {
        return Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    private fun getBaseUrl(environment: Environment): String {
        return when (environment) {
            Environment.DEV -> BASE_URL_DEV
            Environment.STAGING -> BASE_URL_STAGING
            Environment.PROD -> BASE_URL_PROD
        }
    }
}

enum class Environment {
    DEV, STAGING, PROD
}

// Repository
class UserRepository(private val environment: Environment) {
    private val apiService: UserApiService
    
    init {
        val retrofit = NetworkModule.getRetrofit(environment)
        apiService = retrofit.create(UserApiService::class.java)
    }
    
    suspend fun getUserProfile(userId: Int, authToken: String): UserResponse {
        return apiService.getUserProfile(userId, "Bearer $authToken")
    }
}